#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <math.h>

#define MAX_ROOT 1000000
#define MAX_DIV 200000

// simple sieve for primes up to limit
static void sieve(int limit, int **primes, int *primeCount) {
    bool *isComp = (bool*)calloc(limit + 1, sizeof(bool));
    int *temp = (int*)malloc((limit/10 + 10) * sizeof(int)); // over‑estimate
    int cnt = 0;
    for (int i = 2; i <= limit; ++i) {
        if (!isComp[i]) {
            temp[cnt++] = i;
            if ((long long)i * i <= limit) {
                for (int j = i * i; j <= limit; j += i) isComp[j] = true;
            }
        }
    }
    free(isComp);
    *primes = temp;
    *primeCount = cnt;
}

int main() {
    // pre‑compute primes up to 1e6
    int *primes = NULL;
    int primeCnt = 0;
    sieve(MAX_ROOT, &primes, &primeCnt);

    // prime table for divisor counts
    bool *isPrimeDiv = (bool*)calloc(MAX_DIV + 1, sizeof(bool));
    isPrimeDiv[2] = true; // 2 is prime, others will be filled by sieve
    // simple sieve for divisor‑count primality
    for (int i = 2; i <= MAX_DIV; ++i) isPrimeDiv[i] = true;
    isPrimeDiv[0] = isPrimeDiv[1] = false;
    for (int i = 2; i * i <= MAX_DIV; ++i) {
        if (isPrimeDiv[i]) {
            for (int j = i * i; j <= MAX_DIV; j += i) isPrimeDiv[j] = false;
        }
    }

    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long L, R;
        scanf("%llu %llu", &L, &R);
        unsigned int N = (unsigned int)(R - L + 1);
        unsigned long long *rem = (unsigned long long*)malloc(N * sizeof(unsigned long long));
        int *divCnt = (int*)malloc(N * sizeof(int));
        for (unsigned int i = 0; i < N; ++i) {
            rem[i] = L + i;
            divCnt[i] = 1;
        }
        unsigned long long limit = (unsigned long long)sqrt((long double)R) + 1;
        for (int pi = 0; pi < primeCnt && (unsigned long long)primes[pi] <= limit; ++pi) {
            unsigned long long p = (unsigned long long)primes[pi];
            unsigned long long start = (L + p - 1) / p * p;
            for (unsigned long long val = start; val <= R; val += p) {
                unsigned int idx = (unsigned int)(val - L);
                int exp = 0;
                while (rem[idx] % p == 0) {
                    rem[idx] /= p;
                    ++exp;
                }
                if (exp) divCnt[idx] *= (exp + 1);
            }
        }
        int answer = 0;
        for (unsigned int i = 0; i < N; ++i) {
            if (rem[i] > 1) divCnt[i] *= 2; // remaining prime factor
            if (divCnt[i] <= MAX_DIV && isPrimeDiv[divCnt[i]]) ++answer;
        }
        printf("%d\n", answer);
        free(rem);
        free(divCnt);
    }
    free(primes);
    free(isPrimeDiv);
    return 0;
}
